          />

          {/* Center hub */}
          <circle cx="50" cy="50" r="14" fill="url(#appleCenterGrad)" opacity="0.95" />
          <circle cx="50" cy="50" r="9" fill="rgba(255,255,255,0.2)" />

          {/* Flywheel nodes - 8 nodes */}
          {[0, 45, 90, 135, 180, 225, 270, 315].map((angle, i) => {
