            const x = 50 + 39 * Math.cos(rad);
            const y = 50 + 39 * Math.sin(rad);
            const colors = [
              "#22d3ee",
              "#a855f7",
              "#f472b6",
              "#22c55e",
              "#f59e0b",
              "#22d3ee",
              "#a855f7",
